INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60842, $$app.services.ai.agent.agent_tool_monitor::ToolSuccessMonitor$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_tool_monitor.py", "line_start": 53, "line_end": 274, "bases": [], "docstring": "工具成功率監控 — Redis 持久化 + 滑動窗口\n\nRedis Key 結構:\n- agent:tool_stats:{tool_name} — Hash: 累計統計\n- agent:tool_stats:{tool_name}:recent — List: 最近 N 次呼叫 (0/1)\n- agent:tool_stats:degraded — Set: 目前被降級的工具名稱"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61551, $$app.services.ai.search.rag_query_service::RAGQueryService$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/rag_query_service.py", "line_start": 45, "line_end": 327, "bases": [], "docstring": "RAG 查詢服務\n\n使用現有 pgvector 嵌入 (728 篇 768D) 作為知識庫，\n透過 Ollama LLM 生成自然語言回答。\n\n所有閾值從 AIConfig 讀取，system prompt 從 AIPromptManager 讀取。\n\n檢索邏輯已提取至 rag_retrieval.py：\n- expand_query_with_kg(): KG 查詢擴展\n- retrieve_chunks(): 段落級 / 文件級向量檢索\n- build_context(): LLM 上下文建構\n- extract_query_terms(): 查詢詞提取 (jieba)"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61591, $$app.services.ai.search.search_intent_parser::SearchIntentParser$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/search_intent_parser.py", "line_start": 26, "line_end": 446, "bases": [], "docstring": "四組件搜尋意圖解析器\n\nLayer 1: 規則引擎（<5ms）-- 正則模式匹配\nLayer 2: 向量語意匹配（10-50ms）-- 相似查詢復用\nLayer 3: LLM 解析（~500ms）-- 複雜查詢 AI 理解\nMerge: 多層結果合併"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
