INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60610, $$app.services.ai.agent.agent_conversation_memory::ConversationMemory$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_conversation_memory.py", "line_start": 33, "line_end": 501, "bases": [], "docstring": "伺服器端對話記憶 — Redis 持久化\n\nKey 格式: agent:conv:{session_id}\nValue: JSON array of {role, content}\nTTL: 1 小時（每次存取自動延長）\n\n設計原則:\n- Redis 不可用時靜默降級（不影響問答流程）\n- 僅儲存 user/assistant 文字，不存工具中間結果\n- 與前端傳入 history 互斥：有 session_id 用 Redis，否則用 request body\n- max_turns 從 ai_config.rag_max_history_turns 讀取（SSOT）\n- 連線失敗後自動重連（避免一次錯誤永久降級）"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
