INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (342921, $$app.services.ai.agent.agent_critic::AgentCritic$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_critic.py", "line_start": 61, "line_end": 195, "bases": [], "docstring": "Critic agent — 審 query / answer 品質（v6.0 POC）。\n\n與 self_evaluator 區別：\n- self_evaluator: 純規則式（n-gram、entity_alignment）— 快但 superficial\n- AgentCritic:    可選 LLM 反思（成本高但深）— 抓 self_evaluator 抓不到的\n\nv6.0 不啟用 LLM 反思（避免成本爆炸），只用規則式 critique signal。\nv6.1+ 可加 use_llm 參數啟用 LLM 反思。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290487, $$app.services.contract.core::ProjectService$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/contract/core.py", "line_start": 50, "line_end": 404, "bases": ["AuditableServiceMixin"], "docstring": "承攬案件服務 - 工廠模式\n\n所有方法不再需要傳入 db 參數，db session 在建構時注入。\n\nExample:\n    service = ProjectService(db)\n\n    # 列表查詢\n    result = await service.get_projects(query_params, current_user)\n\n    # 建立\n    project = await service.create(ProjectCreate(project_name=\"新專案\"))\n\n    # 更新\n    project = await service.update(1, ProjectUpdate(stat$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60695, $$app.services.ai.agent.agent_orchestrator::AgentOrchestrator$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_orchestrator.py", "line_start": 61, "line_end": 655, "bases": [], "docstring": "Agentic 文件檢索引擎\n\nSSE 事件格式：\n  data: {\"type\":\"thinking\",\"step\":\"...\",\"step_index\":N}\n  data: {\"type\":\"tool_call\",\"tool\":\"...\",\"params\":{...},\"step_index\":N}\n  data: {\"type\":\"tool_result\",\"tool\":\"...\",\"summary\":\"...\",\"count\":N,\"step_index\":N}\n  data: {\"type\":\"sources\",\"sources\":[...],\"retrieval_co$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60733, $$app.services.ai.agent.agent_planner::AgentWorkingMemory$$, $$py_class$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_planner.py", "line_start": 49, "line_end": 75, "bases": [], "docstring": "智能體工作記憶 — 追蹤本次問答的推理鏈。\n\n用途：\n- scratchpad: ReAct 各輪推理摘要（供 LLM 回顧）\n- discovered_entities: 已發現的實體名稱（避免重複查詢）\n- confidence: 目前答案信心度（0-1，由 LLM 評估）\n- total_results: 累計結果數量"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
