INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61567, $$app.services.ai.search.reranker::_adaptive_weights$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/reranker.py", "line_start": 47, "line_end": 65, "args": ["query_terms"], "is_async": false, "is_private": true, "docstring": "Adaptive weights based on query characteristics.\n\nShort queries (1-2 terms): favor keyword matching (precision)\nMedium queries (3-5 terms): balanced\nLong queries (6+ terms): favor semantic (recall)\n\nReturns:\n    (vector_weight, keyword_weight, llm_weight)"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61568, $$app.services.ai.search.reranker::compute_keyword_score$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/reranker.py", "line_start": 68, "line_end": 111, "args": ["query_terms", "doc_text"], "is_async": false, "is_private": false, "docstring": "計算關鍵字覆蓋度分數 (0-1)\n\n策略：\n- 精確匹配：查詢詞完全出現在文件中 → 高分\n- 部分匹配：查詢詞的子字串出現 → 部分分\n- IDF 加權：罕見詞命中比常見詞更重要"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
