INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290913, $$app.services.integration.line_push_scheduler::LinePushScheduler._get_push_targets$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/integration/line_push_scheduler.py", "line_start": 176, "line_end": 205, "args": [], "is_async": true, "is_private": true, "docstring": "從 DB 查詢啟用 LINE 通知的使用者。\n\nv6.3 體感修法（解「被動等問」斷鏈）：\n- 原邏輯：DB User 無 line_user_id → 回空 → push 0 人 → owner 永遠收不到\n- 新邏輯：DB 空時用 LINE_ADMIN_USER_ID env fallback（owner 至少收得到）\n- ENV gate：LINE_PROACTIVE_NOTIFY_ENABLED=false 顯式關閉\n\n查詢 User 表的 line_user_id 欄位（若已建立）；空時用 env fallback。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
