INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (565866, $$app.repositories.calendar_repository::CalendarRepository._alias_user_filter$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/repositories/calendar_repository.py", "line_start": 40, "line_end": 73, "args": ["user_id"], "is_async": true, "is_private": true, "docstring": "P0-A + v6.10.1: 返回 or_(assigned IN alias, created_by IN alias, owner-less) 條件。\n\n替代 4 處重複的 `or_(assigned_user_id == user_id, created_by == user_id)`，\n後者只比對單一 user_id，會漏 alias group（同人多帳號分支建的事件看不到）。\n\nv6.10.1 急救（2026-05-20）：加 NULL owner fallback —\n  觸發案例：公文 2479 事件 1081 用戶看不到 → 揭發 883/984 (90%) 事件 ow$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
