INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61560, $$app.services.ai.search.rag_retrieval::expand_query_with_kg$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/rag_retrieval.py", "line_start": 32, "line_end": 77, "args": ["db", "query_terms"], "is_async": true, "is_private": false, "docstring": "使用知識圖譜擴展查詢詞彙。\n\n透過 search_entity_expander 統一管道：\n1. SynonymExpander — ai_synonyms 表同義詞擴展\n2. Knowledge Graph — canonical_entities + entity_aliases 別名擴展\n\n若查詢提到的實體存在於 KG 中，其別名和同義詞會被加入搜尋詞，\n讓向量搜尋能找到用不同名稱提及同一實體的文件。\n\nArgs:\n    db: 資料庫 session\n    query_terms: 從查詢中提取的搜尋詞彙\n\nReturns:\n    擴展$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
