INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60747, $$app.services.ai.agent.agent_planner::AgentPlanner.react$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_planner.py", "line_start": 525, "line_end": 665, "args": ["question", "tool_results", "memory", "context"], "is_async": true, "is_private": false, "docstring": "ReAct（Reason + Act）循環 — LLM 驅動的多步推理。\n\n觀察工具結果 → LLM 判斷：\n- action=\"answer\"   → 結果充分，進入合成\n- action=\"continue\" → 需要查詢更多資料\n- action=\"refine\"   → 用不同參數重試\n\n僅在 auto_correct 未觸發時呼叫（作為慢路徑）。\n\nReturns:\n    修正後的 plan dict（含 tool_calls），或 None 表示結果充分"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
