INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60751, $$app.services.ai.agent.agent_post_processing::self_evaluate_and_evolve$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_post_processing.py", "line_start": 119, "line_end": 200, "args": ["question", "answer", "tool_results", "trace", "citation_result", "context"], "is_async": true, "is_private": false, "docstring": "自我評估 + 自動進化觸發。\n\n每次回答後自動執行：\n1. 評估本次回答品質 -> 產生改進信號\n2. 檢查是否達到進化觸發條件 (每 50 次 / 每 24h)\n3. 若觸發，自動執行進化動作（升級種子/降級模式/清理）"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60752, $$app.services.ai.agent.agent_post_processing::_learn_tool_combo$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_post_processing.py", "line_start": 203, "line_end": 236, "args": ["ctx", "success"], "is_async": true, "is_private": true, "docstring": "學習工具組合模式 — 追蹤哪些工具組合在特定場景下成功/失敗。\n\n以 AgentLearning(learning_type='tool_combo') 持久化，\n讓 inject_cross_session_learnings 在未來查詢中提供工具組合建議。\n\n2026-04-20 修：不可用 ctx.db（request session），此函式透過\nasyncio.create_task 背景執行；FastAPI request 結束時 get_async_db\n會 commit session，若此 task 還在用 → asyncpg 'anot$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (59876, $$app.api.endpoints.ai.graph_admin_code::analyze_architecture$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/api/endpoints/ai/graph_admin_code.py", "line_start": 153, "line_end": 174, "args": ["current_user", "db"], "is_async": true, "is_private": false, "docstring": "分析代碼架構，產出以下洞察：\n\n- 高耦合模組（出向依賴最多）\n- 樞紐模組（被匯入最多）\n- 大型模組（行數最多）\n- 孤立模組（無入向匯入）\n- 巨型類別（方法數最多）"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
