INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60594, $$app.services.ai.agent.agent_chitchat::is_chitchat$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_chitchat.py", "line_start": 117, "line_end": 154, "args": ["text", "context"], "is_async": false, "is_private": false, "docstring": "判斷是否為閒聊/非文件查詢\n\n策略：反向偵測 — 檢查是否包含公文業務關鍵字\n- 有業務關鍵字 → 不是閒聊 → 走 Agent 工具流程\n- 沒有業務關鍵字 → 視為閒聊 → 走輕量 LLM 對話\n\nArgs:\n    context: 助理上下文。「agent」上下文跳過短句閒聊判定，\n             因為乾坤智能體的問題天然偏向分析性質。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
