INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61080, $$app.services.ai.document.entity_extraction_service::get_extracted_document_ids$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/document/entity_extraction_service.py", "line_start": 91, "line_end": 105, "args": ["db"], "is_async": true, "is_private": false, "docstring": "取得所有已提取實體的公文 ID（單次查詢，避免 N+1）\n\n批次處理時可先呼叫此函式取得已完成的 ID 集合，\n再用 ``doc_id in extracted_ids`` 快速跳過，\n避免對每筆公文各發一次 COUNT 查詢。\n\nArgs:\n    db: 資料庫 session\n\nReturns:\n    已存在 DocumentEntity 記錄的 document_id 集合"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (331472, $$app.services.ai.agent.agent_self_evaluator::AgentSelfEvaluator._extract_named_entities_from_query$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_self_evaluator.py", "line_start": 318, "line_end": 332, "args": ["question"], "is_async": false, "is_private": true, "docstring": "從 query 抽具名 entity（hallucination 偵測用）。\n\nv5.11 Phase 3 — 簡單啟發式，不依賴 NER engine。\n若 query 含具名 entity 但 answer 不提，視為 hallucination 警示。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61094, $$app.services.ai.document.extraction_scheduler::ExtractionScheduler._process_batch$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/document/extraction_scheduler.py", "line_start": 253, "line_end": 408, "args": [], "is_async": true, "is_private": true, "docstring": "處理一批待提取的公文。\n\n流程:\n0. 檢查 Ollama 可用性，決定文檔間休眠時間\n1. 取得已提取 ID 集合（排除用）\n2. 查詢待提取公文（limit BATCH_LIMIT）\n3. 逐筆 NER 提取 + 入圖\n4. 每 COMMIT_EVERY 筆 commit\n5. 斷路器：連續失敗達閾值時停止"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
