INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (331473, $$app.services.ai.agent.agent_self_evaluator::AgentSelfEvaluator._eval_query_entity_alignment$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_self_evaluator.py", "line_start": 334, "line_end": 360, "args": ["question", "answer"], "is_async": false, "is_private": true, "docstring": "偵測 query 具名 entity 與 answer 的對齊度。\n\nReturns:\n    1.0 = query 無具名 entity（無從判斷，無扣分）\n    1.0 = query 有具名 entity 且全在 answer 中\n    0.0 = query 有具名 entity 但 answer 完全沒提（hallucination 高度警示）\n\n範例（v5.10.2 觀察案例）：\n    Q: 「承辦人老蕭負責的案件有哪些？」\n    A: （列了 6 個無關公文，完全沒提「蕭」字）\n    → 抽出「老蕭」/「蕭」，ans$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61142, $$app.services.ai.domain.cross_domain_matcher::CrossDomainMatchEngine.find_best_match$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/cross_domain_matcher.py", "line_start": 52, "line_end": 95, "args": ["name", "candidates", "threshold", "use_false_match_check"], "is_async": true, "is_private": false, "docstring": "在候選清單中尋找最佳匹配（trigram → 語意向量回退）。\n\nStage 1: CanonicalEntityMatcher.compute_similarity (Python 端 trigram)\nStage 2: 若 trigram 無匹配且 pgvector 啟用，以 cosine_distance 嘗試語意匹配\n\nReturns:\n    (best_entity, best_score) — 無匹配時回傳 (None, 0.0)"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
