INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61181, $$app.services.ai.domain.morning_report_service::MorningReportService._get_dispatch_deadlines$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/morning_report_service.py", "line_start": 567, "line_end": 612, "args": ["today", "week_later"], "is_async": true, "is_private": true, "docstring": "到期派工（本週+今日）— 以作業進度 + 公文對照為基準。\n\n三層結案判定（closure_level）：\n- closed / delivered → 完全排除（L1+L2，系統結案或成果已交付）\n- pending_closure → 排除到期清單（已實質完成，僅差補結案）\n- active → 列入，標註作業進度標籤"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61182, $$app.services.ai.domain.morning_report_service::MorningReportService._get_overdue_items$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/morning_report_service.py", "line_start": 665, "line_end": 752, "args": ["today"], "is_async": true, "is_private": true, "docstring": "逾期判定（同到期邏輯）：\n\n以「作業進度 + 公文對照狀態期限」為基準（不依賴 batch_no）。\n三層結案判定：\n- L1 closed/L2 delivered → 完全排除\n- L3 pending_closure → 拆到 pending_closure_items（待結案確認）\n- active → 真正逾期"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
