INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60826, $$app.services.ai.agent.agent_synthesis::AgentSynthesizer.synthesize_answer$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "line_start": 40, "line_end": 231, "args": ["question", "tool_results", "history", "context", "cross_session_hints"], "is_async": true, "is_private": false, "docstring": "根據所有工具結果，串流生成最終回答。\n\nv6.3 體感型輸出：cross_session_hints 為同 user 過去 30 天最近 5 次 query。\n若提供且與本問題相關，synthesis 會在回應第一句明確 acknowledge\n「上次（日期）你問過 X」— 解決「沒有延續性」體感斷鏈。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60827, $$app.services.ai.agent.agent_synthesis::AgentSynthesizer._quality_review$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "line_start": 233, "line_end": 324, "args": ["question", "answer", "tool_results"], "is_async": true, "is_private": true, "docstring": "Review and improve answer quality before sending.\n\nChecks:\n1. Does the answer actually address the question?\n2. Are statistics properly contextualized (not just raw numbers)?\n3. Are there actionable suggestions?\n4. Is the format readable?\n\nIf quality is low, ask LLM$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61204, $$app.services.ai.federation.federation_client::FederationClient.query_external$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/federation/federation_client.py", "line_start": 103, "line_end": 196, "args": ["system_id", "question", "context", "timeout"], "is_async": true, "is_private": false, "docstring": "向外部聯邦 AI 系統發送 Schema v1.0 查詢\n\nArgs:\n    system_id: 系統識別碼 (如 \"openclaw\", \"lvrland\", \"tunnel\")\n    question: 查詢問題\n    context: 附加上下文 (可選)\n    timeout: 請求超時秒數\n\nReturns:\n    { system, success, answer, tools_used, latency_ms, error }"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (378434, $$app.services.ai.agent.agent_synthesis::AgentSynthesizer._fact_check_numbers$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "line_start": 326, "line_end": 375, "args": ["answer", "tool_results"], "is_async": false, "is_private": true, "docstring": "F19 (5/04 v3.0 覆盤洞察 12)：偵測 LLM 編造數字。\n\n策略：\n1. 從 answer 提 ≥3 位數字（小數字過多 false positive）\n2. 從 tool_results 提所有出現過的數字（含 dict values）\n3. 標記 answer 中數字不在 source 集合的（potential hallucination）\n4. 僅 log warning（不改 answer，避免 over-correction）\n\n對應事故：5/03 14:00:40 LLM 回「知識圖譜共 3 個實體」但 tool 回 $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (566009, $$app.services.ai.agent.agent_synthesis::AgentSynthesizer._should_inject_graph_context$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "line_start": 393, "line_end": 429, "args": ["question", "context", "tool_results"], "is_async": false, "is_private": true, "docstring": "決定是否注入 KG / Wiki context。\n\n2026-05-16 retro 改善 3：每 query 強制 2-hop KG traversal + wiki search →\n短/簡單 query 是純浪費（p95=65s 退化的元兇之一）。\n\nSkip 條件（滿足任一即 False）：\n\n1. ``question`` 過短（trim 後 < 6 字）— 多半閒聊或極簡 stat\n2. ``context == \"chitchat\"`` — 閒聊不需要 KG context\n3. ``tool_res$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (182684, $$app.services.ai.agent.agent_synthesis::AgentSynthesizer._inject_wiki_context$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "line_start": 477, "line_end": 516, "args": ["question"], "is_async": true, "is_private": true, "docstring": "Wiki-RAG: 從 LLM Wiki 檢索相關 narrative，注入合成上下文。\n\n2026-04-19 新增：補 KG + Wiki 雙源融合缺口。\n- 原本 Wiki 只在 rag_retrieval 路徑被使用，agent 走 tool 路徑時 wiki 完全不被讀\n- 此函數讓 synthesis 階段**無條件**查 wiki（若命中 top 3）\n- 每筆限 300 字，避免 prompt 過長"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
