INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (331496, $$app.services.memory.crystallizer::Crystallizer._confidence_score$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/memory/crystallizer.py", "line_start": 123, "line_end": 139, "args": ["meta"], "is_async": false, "is_private": true, "docstring": "從 pattern meta 計算 auto-apply confidence。\n\n綜合 hit_count（流量）+ success_rate（品質）：\n- hit ≥ 15 飽和到 hit_factor=1.0\n- success_rate 直接乘上 hit_factor\n\n舉例：\n- hit=6,  succ=1.00 → 0.40 * 1.00 = 0.40（low — 留 owner 批）\n- hit=10, succ=1.00 → 0.67 * 1.00 = 0.67（middle）\n- hit=15, succ=1.00 → 1.00 * 1.00 = 1.00（high → $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
