INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (182798, $$app.services.memory.diary_service::DiaryService.append_entry$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/memory/diary_service.py", "line_start": 96, "line_end": 177, "args": [], "is_async": true, "is_private": false, "docstring": "追加一筆日記 entry（fire-and-forget，失敗只 log 不 raise）。\n\nv6.5 I2：每筆 entry 加 entities 行（NER 抽 question + answer），\n補 KG ↔ Memory Wiki ❺ 弱連結。reuse critic 的 NER pattern（人名暱稱\n/案件編號/派工單號）。grep `entities.*老蕭` 即可統計提及次數。\n\nR7 (v6.9 / 2026-05-08)：解 v3.0 洞察 11 silent skip 反模式\n- file_io 失敗 retry 1 次（檔案系統 transient 錯誤）\n- "}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (441347, $$app.services.memory.diary_service::DiaryService._write_with_retry$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/memory/diary_service.py", "line_start": 179, "line_end": 202, "args": ["path", "entry"], "is_async": true, "is_private": true, "docstring": "寫入失敗 retry 1 次（解檔案系統 transient 錯誤）。\n\nR7 (v6.9)：原 fire-and-forget 對 transient 失敗無防禦，\n加 1 次 retry + 0.1s 短等可解大部分 EAGAIN/EBUSY 案例。\n最終仍失敗時 raise，由 caller append_entry 的 except 捕獲計數。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (134277, $$app.services.ai.domain.morning_report_service::MorningReportService._get_upcoming_meetings$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/morning_report_service.py", "line_start": 953, "line_end": 996, "args": ["today", "week_later"], "is_async": true, "is_private": true, "docstring": "近期會議（不含現勘）。\n\n擴大涵蓋 event_type IN ('meeting', 'review')，避免「審查會議」被歸到\nreview 而漏掉（CalendarEventAutoBuilder KEYWORD 規則順序：審查 > 會議）。\nreview 類別需 title 含會議/開會字樣才納入；純「[審查]」公文不算。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
