INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290927, $$app.services.integration.telegram_bot::TelegramBotService.handle_text_message$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/integration/telegram_bot.py", "line_start": 69, "line_end": 180, "args": ["chat_id", "user_id", "text", "username", "user_message_id"], "is_async": true, "is_private": false, "docstring": "處理文字訊息 — 互動式體驗 (agent-broker 風格)\n\n1. 在使用者訊息上加 👁️ 反應 (已收到)\n2. 回覆串接：reply_to 使用者訊息\n3. Edit-streaming：每 1.5s 更新同一則訊息\n4. 工具執行時切換反應 emoji\n5. 完成時加 ✅ + 工具摘要"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
