INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290934, $$app.services.integration.telegram_bot::TelegramBotService.push_message$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/integration/telegram_bot.py", "line_start": 395, "line_end": 421, "args": ["chat_id", "text"], "is_async": true, "is_private": false, "docstring": "主動推播訊息（ADR-0027：受 TELEGRAM_ADMIN_PUSH_ENABLED 控制）\n\n與 send_message 的差別：\n- send_message = 被動回覆（用戶先發訊息 → 回應）\n- push_message = 主動推播（晨報 / 告警 / 結晶提案）\n\n2026-04-21 Telegram 個人號封禁後，push_message 預設關閉；\n被動 webhook（send_message）保留可用。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
