INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (581643, $$app.api.endpoints.auth.sso_bridge::sso_bridge$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/api/endpoints/auth/sso_bridge.py", "line_start": 54, "line_end": 208, "args": ["request", "db"], "is_async": true, "is_private": false, "docstring": "SSO Bridge 端點\n\n成功（200）：返回 TokenResponse 並設定 Missive httpOnly cookies\n失敗：\n    - 503 CK_SSO_ENABLED=false（功能未啟用）\n    - 401 cookie 缺失或 JWT 驗證失敗\n    - 403 員工無 missive 系統權限 / 帳號未啟用\n    - 404 SSO email 不在 Missive User table（員工需先用原方式登入過）"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
