INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (695138, $$app.core.ck_sso::verify_ck_sso_jwt_rs256$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/ck_sso.py", "line_start": 94, "line_end": 166, "args": ["token", "jwks_url"], "is_async": false, "is_private": false, "docstring": "驗證 RS256 簽章 JWT（ADR-0003 W2+，從 ck_employee_rs cookie 取得）。\n\n流程：\n    1. 解 JWT header 取 kid\n    2. 從 jwks_url fetch JWKS（in-memory cache 1hr）\n    3. 用對應 kid 公鑰驗 RS256\n    4. 驗 iss / exp / required claims\n    5. return CKSSOEmployee 或 None\n\nFailure modes:\n    - jwks fetch fail → return None（caller 可 fal"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (695140, $$app.core.ck_sso::verify_ck_sso_jwt_auto$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/ck_sso.py", "line_start": 222, "line_end": 267, "args": ["cookies", "secret", "jwks_url"], "is_async": false, "is_private": false, "docstring": "智能 dispatcher（v2.0 推薦）：\n\n1. 優先取 ck_employee_rs cookie → 用 RS256 path（jwks 公鑰）\n2. fallback 取 ck_employee cookie → 用 HS256 path（CK_SSO_JWT_SECRET）\n3. 兩個都失敗 → return None\n\n使用情境：\n    - W2~W7 過渡期：兩 cookie 都會被 CF Pages 設，dispatcher 自然優先 RS256\n    - W8+：CF Pages 只設 ck_employee_rs，HS path 自然 idle\n$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
