INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (161975, $$app.core.scheduler::llm_quota_check_job$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/scheduler.py", "line_start": 1298, "line_end": 1386, "args": [], "is_async": true, "is_private": false, "docstring": "LLM 統一告警（2026-04-19 整合）：三維度一次 Telegram 推送。\n\n**整合 3 維度**：\n  1. Groq per-day request（對應 free tier 每日上限）\n  2. NVIDIA per-month credits（對應 NIM 免費額度）\n  3. Token 總成本（日 USD cost ceiling）\n\n每日每維度僅告警一次（去重 via ``_LLM_QUOTA_ALERT_FLAGS``）。\n\nenv 配置:\n  GROQ_DAILY_REQ_LIMIT        Groq free tier 每日請求上限（預設 1000）\n  "}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
