INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (208710, $$app.core.scheduler::memory_anti_echo_scan_job$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/scheduler.py", "line_start": 1423, "line_end": 1472, "args": [], "is_async": true, "is_private": false, "docstring": "反迴聲室協議 — 每週一 06:00 掃近 7 天 diary，偵測過度一致。\n\n2026-04-21 v5.8.0 坤哥意識體 D5-A。\n\n觸發條件（預設）：\n- 7 天內 ≥ 20 筆 diary entry\n- success_rate ≥ 90%\n- failure ≤ 2\n- 3 天內未觸發過（cooldown）\n\n觸發後在當日 diary append「反迴聲室」段落，列 1-3 條質疑候選。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (354035, $$app.core.scheduler::daily_self_reflection_line_push_job$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/scheduler.py", "line_start": 1476, "line_end": 1533, "args": [], "is_async": true, "is_private": false, "docstring": "v6.6 Phase B2 (5c)：每日 22:00 彙總當日自我反思推 LINE owner。\n\n解體感「anti_echo 觸發即推會變雜訊」— 改每日彙總一次。\n\n來源：今日 diary 中的「反迴聲室」段落 + 失敗 query 統計。\n無觸發、無失敗 → silent skip（不推「沒事」雜訊）。\n\nENV：\n- LINE_ADMIN_USER_ID 未設 → silent skip\n- LINE_GROWTH_NOTIFY_ENABLED=false → 顯式關閉"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
