INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (354039, $$app.core.scheduler::soul_mirror_sync_job$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/scheduler.py", "line_start": 1699, "line_end": 1747, "args": [], "is_async": true, "is_private": false, "docstring": "SOUL.md 跨 repo 自動同步（v6.4 C1）— 每日 04:45。\n\n為何自動：\n- soul_mirror_drift_check.py 已偵測 drift，但同步腳本 sync_soul_to_hermes.sh\n  原為 manual gate（owner 手動跑 --apply）→ 跨通道人格漂移持續存在\n- Web 用戶看 Missive SOUL，Telegram/LINE 用戶看 Hermes SOUL，內容不同步\n- 跨 repo 寫檔風險評估後接受：cp 是 reversible（AaaP 端 git 可回溯）\n\n安全閘：\n- 只覆蓋 ../CK_AaaP/run"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (182617, $$app.db.database::run_with_fresh_session_no_commit$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/db/database.py", "line_start": 155, "line_end": 162, "args": ["fn"], "is_async": true, "is_private": false, "docstring": "供 callee 自己 commit 的情境（e.g. save_trace 內部已 commit/rollback）。\n\n外層再 commit 會得 'This transaction is closed' 錯誤。因此此版本只負責\nsession lifecycle，commit/rollback 由 callee 負責。"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (365574, $$app.core.scheduler::cron_self_health_alert_job$$, $$py_function$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/scheduler.py", "line_start": 1537, "line_end": 1609, "args": [], "is_async": true, "is_private": false, "docstring": "v6.7 E4：cron 自我健康檢查推 LINE owner（每日 06:30）。\n\n解體感「fitness step 13 偵測 cron 健康但只 log 不推 LINE」斷鏈\n（與 v6.6 5a/5b/5c 對齊：所有重要事件都該 LINE 體感）。\n\n判定規則：\n- failed >= 1 → 推 LINE「⚠ cron 異常通知」（含失敗 cron 名稱）\n- never_run >= total / 2 → 推 LINE「⚠ 多數 cron 從未執行」（系統剛重啟）\n- 全綠 → silent（不推「沒事」雜訊）\n\nENV 共用：\n- LINE_ADMIN_USER_ID 未設"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
