INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290592, $$app.services.document.receiver_normalizer$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/document/receiver_normalizer.py", "lines": 177, "docstring": "收發文單位正規化服務\n\n將 documents.sender/receiver 欄位中的多種格式變體正規化：\n- 去除統編前綴 (如 \"EB50819619 乾坤測繪科技有限公司\" → \"乾坤測繪科技有限公司\")\n- 去除機關代碼括號 (如 \"380110000G (桃園市政府工務局)\" → \"桃園市政府工務局\")\n- 拆分管道分隔的多受文者 (如 \"A|B|C\" → primary=\"A\", cc=[\"B\",\"C\"])\n- 處理換行符 (如 \"EB50819619\\n乾坤測繪科技有限公司\" → \"乾坤測繪科技有限公司\")\n- 去除代表人後綴 (如 \"乾坤測繪科技有限公司(張坤樹)\" → \"乾坤測繪科技有限公司\")\n- 去除協力廠商資訊 (如 \"...（協力廠商:大有國際...）$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
