INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (394786, $$app.services.security.scanner$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/security/scanner.py", "lines": 318, "docstring": "自動安全掃描服務\n\n定期掃描專案程式碼，偵測常見資安問題並寫入 DB。\n整合至 scheduler.py 每日排程。\n\n掃描項目：\n1. 硬編碼密鑰偵測（API Key、Token、Password）\n2. SQL 注入風險（字串拼接 SQL）\n3. 不安全函數使用（eval、exec、pickle）\n4. 缺少認證裝飾器的端點\n5. pip/npm 依賴漏洞（audit）\n\nVersion: 1.0.0\nCreated: 2026-03-27", "mtime": 1779085268.3003254, "class_count": 2, "function_count": 0, "method_count": 8, "is_async_module": true, "outgoing_deps": 0, "incoming_deps": 0$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
