INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (208868, $$app.services.common.calendar_title_template$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/common/calendar_title_template.py", "lines": 258, "docstring": "Calendar Event Title Template (ADR-0026 v5.8.1).\n\n集中化日曆事件標題規則，讓公文事件、派工事件、手動事件走同一模板。\n\n**標準格式**：\n```\n【{category}】{verb}派工單號{no3}({team_abbr})_{project_name}_{item}\n```\n\n**範例**：\n```\n【成果】提交派工單號020(全國)_中壢區南園二路延伸中豐北路道路新闢工程_徵收市價報告\n【會議通知】召開派工單號003(全國)_中壢區龍岡路4-1-10M計畫道路路口瓶頸打通工程_協議價購市價審查會議\n【會勘通知】辦理派工單號021(乾坤)_中壢區大華路(內定一街至大華路350巷)道路拓寬工程_現勘會勘\n【派工通知】接收派工單號006(冠誠)_桃園區鹽庫西街至春$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (157099, $$app.core.inference_provider_context$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/inference_provider_context.py", "lines": 36, "docstring": "Inference Provider ContextVar — 紀錄當前請求最後一次成功推理的實體 provider。\n\n解決 shadow_logger 的 provider 欄位只反映「channel 標籤」（如 ``gemma-local``、\n``gemma-hermes``）而不是實體 LLM（``groq`` / ``ollama`` / ``nvidia``）的問題。\n\n使用方式：\n    ai_connector 在 record_completion 時呼叫 ``set_actual_provider(provider)``；\n    shadow_logger.log_trace 若 caller 未明確傳入 ``actual_llm_provider``，\n    會自動從 ContextVar 讀當前請求的實體 prov$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (208921, $$app.services.taoyuan.work_record_calendar_sync$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/taoyuan/work_record_calendar_sync.py", "lines": 231, "docstring": "WorkRecord ↔ Calendar Sync Service (ADR-0026).\n\nv5.8.0：work_record.deadline_date 設定時自動 upsert document_calendar_events。\n\n設計原則（v5.8.1 升級）：\n- **單一真相**：一個 document 最多對應一個 event（業務鍵 = document_id）\n- **Document-first dedup**：若 document 已有 event，work_record 僅更新期限，不建重複\n- **Title 優先序**（資訊密度由高至低）：\n    1. work_record.description（使用者明確描述）\n    2. `[{category}]: {doc.subject$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290957, $$app.services.notification.dispatcher$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/notification/dispatcher.py", "lines": 222, "docstring": "統一通知派發器 — LINE / Discord / Telegram 多通道推送\n\n集中管理所有主動推送：截止日提醒、預算警報、系統異常等。\n各通道自動適配格式（LINE Flex / Discord Embed / Telegram Markdown / 純文字回退）。\n\nUsage:\n    dispatcher = NotificationDispatcher()\n    await dispatcher.send_deadline_alert(user, doc_subject, deadline)\n    await dispatcher.send_budget_alert(user, project_name, amount)\n    await dispatcher.broadcast_system_alert(messa$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60766, $$app.services.ai.agent.agent_router$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_router.py", "lines": 394, "docstring": "Agent Router — 輕量路由層\n\n在 LLM 規劃前攔截可直接路由的查詢，降低 50%+ 查詢的延遲。\n\n路由優先級：\n1. Chitchat 短路 — is_chitchat() (已有)\n2. Pattern Match — 歷史成功模式 (confidence >= threshold)\n2.5. Gemma 4 語意意圖分類 — 輕量 LLM 單次呼叫\n3. Fallthrough → LLM Planning（現有流程）\n\n設計原則：\n- 只在高信心時攔截（寧可多走 LLM，不可規劃錯誤）\n- 所有路由決策記錄至 AgentTrace\n- 降級工具自動過濾\n- Layer 1~2 路由決策 < 10ms（零 LLM 呼叫）\n- Layer 2.5 Gemma 4 為增強層，失敗不影響現有流程\n\nVersio$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
