INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (182750, $$app.services.memory.autobiography$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/memory/autobiography.py", "lines": 731, "docstring": "Autobiography Generator — Agent 週自傳（第一人稱成長敘述）\n\n2026-04-19 Memory Wiki Phase 4。\n\n流程：\n1. collect_week_signals - 聚合本週量能 (traces/patterns/crystals/failures)\n2. generate_narrative - LLM 第一人稱寫 200-400 字\n3. validate_narrative - 品質閘\n4. persist_autobiography - 寫 wiki/memory/evolutions/YYYY-WNN.md\n5. push_to_telegram - Telegram 通知\n6. update_soul_growth - SOUL.md 成長段落自動追加（agent_writab$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
