INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60748, $$app.services.ai.agent.agent_post_processing$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_post_processing.py", "lines": 472, "docstring": "Agent 後處理模組 — 從 agent_orchestrator.py 提取\n\n負責查詢完成後的非核心處理：\n1. 引用核實 (citation validation)\n2. 品質自省 (self-reflection)\n3. 對話記憶儲存 + 摘要壓縮\n4. 使用者偏好萃取\n5. 追蹤持久化 (trace → monitor + DB)\n6. 模式學習 (pattern learning)\n7. 查詢興趣追蹤 (query tracking)\n8. 自我評估 + 自動進化 (self-evaluation + evolution)\n\nVersion: 1.0.0\nCreated: 2026-03-18\nExtracted from: agent_orchestrator.py v2.5.0", "mtime"$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
