INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60863, $$app.services.ai.agent.agent_trace$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_trace.py", "lines": 284, "docstring": "Agent Trace — 結構化追蹤記錄\n\n每次問答產生完整 Trace，用於：\n- 效能分析（哪個工具最慢？）\n- 規劃品質（規劃成功率、修正觸發率）\n- 資源消耗（LLM 呼叫次數、token 用量估算）\n- 異常偵測（超時率、錯誤率）\n\n設計原則：\n- 零侵入：Orchestrator 只呼叫 trace.record_*()\n- 輕量：不額外呼叫 DB/Redis，僅 in-memory 收集\n- 可擴展：未來可接 OpenTelemetry / Prometheus\n\nVersion: 1.0.0\nCreated: 2026-03-14", "mtime": 1776617964.447754, "class_count": 2, "function_count": 0, "method_count": 14, "is_a$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
