INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60597, $$app.services.ai.agent.agent_conductor$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_conductor.py", "lines": 408, "docstring": "Conductor Agent — Parallel sub-task orchestration.\n\nWhen a query spans multiple domains (e.g., \"比較桃園工務局的派工數量和公文數量\"),\nthe Conductor:\n1. Decomposes into independent sub-tasks\n2. Assigns each to a specialized role (DOC/DISPATCH/PM/ERP/GRAPH)\n3. Executes sub-tasks in parallel via asyncio.gather\n4. Merges results into a unified response\n\nActivation: Triggered by AgentSuperv$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
