INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (291067, $$app.services.tender.pcc_today_scraper$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/tender/pcc_today_scraper.py", "lines": 271, "docstring": "PCC 政府電子採購網今日標案爬蟲 — 主要資料來源\n\n直接爬取 web.pcc.gov.tw 今日標案頁面，取得全量標案資料。\nPCC 為權威來源 (633+ 筆/日)，ezbid 退為補充/備援。\n\n資料來源: https://web.pcc.gov.tw/prkms/today/common/todayTender\n每日公告分類:\n  - 公開招標公告 (~633)\n  - 限制性招標 (~111)\n  - 選擇性招標(個案) (~10)\n  - 選擇性招標(後續邀標) (~677)\n  - 公開取得報價單/企劃書 (~406)\n  - 更正公告 (~84)\n\nVersion: 1.0.0\nCreated: 2026-04-09", "mtime": 1777326057.167251, "class_count": $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
