INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (314348, $$app.api.endpoints.ai.morning_report$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/api/endpoints/ai/morning_report.py", "lines": 206, "docstring": "晨報操作 API — Morning Report Operations 領域\n\n從 ai_stats.py 抽出（領域驅動分治）。\n這完全不是 stats — 是晨報的生成、推送、歷史快照、派送觀測性。\n\n端點:\n- POST /ai/stats/morning-report/preview — 晨報預覽（不推送）\n- POST /ai/stats/morning-report/push — 手動推送（含 delivery log + 字數截斷保護）\n- POST /ai/stats/morning-report/history — 近 14 天 snapshot 列表（B4）\n- POST /ai/stats/morning-report/status — 近 7 天 delivery log + 連續失敗天數（A1）", "mtime$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
