INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61550, $$app.services.ai.search.rag_query_service$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/rag_query_service.py", "lines": 327, "docstring": "RAG (Retrieval-Augmented Generation) 查詢服務\n\n基於現有 pgvector 向量搜尋 + Ollama LLM 的輕量 RAG 管線：\n1. 查詢 embedding 生成 (EmbeddingManager)\n2. 知識圖譜查詢擴展 (KG neighbor expansion)\n3. 向量相似度檢索 (documents.embedding cosine_distance)\n4. 上下文建構 + LLM 回答生成 (AIConnector, prefer_local)\n5. 來源引用追蹤\n6. 多輪對話上下文 (conversation history)\n7. SSE 串流回答\n\nVersion: 2.5.0\nCreated: 2026-02-25\nUpdated: 2026-03$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
