INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (182806, $$app.services.memory.narrative_validator$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/memory/narrative_validator.py", "lines": 100, "docstring": "Narrative Validator — 週自傳品質閘\n\n2026-04-19 Memory Wiki Phase 4。\n\n檢查：\n- 長度 100~600 字\n- 不含簡體字（常見字符檢測）\n- 不含 API key / token / URL 模式\n- 至少含 1 個具體數字（query 數/成功率/案號）\n- 不超過 3 個模糊詞（「可能」「大概」「或許」）", "mtime": 1776605361.9066641, "class_count": 1, "function_count": 1, "method_count": 0, "is_async_module": false, "outgoing_deps": 0, "incoming_deps": 0, "layer": "services"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61566, $$app.services.ai.search.reranker$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/reranker.py", "lines": 360, "docstring": "檢索結果重排序服務\n\n三層混合重排策略：\n1. 向量相似度 (已有，由 pgvector cosine_distance 提供)\n2. 關鍵字覆蓋度 (BM25-like 精確匹配)\n3. LLM 相關性評分 (Gemma 4 預設啟用，>5 筆自動觸發)\n\n最終分數 = w_vector * vector_sim + w_keyword * keyword_score + w_llm * llm_score\n\nVersion: 2.0.0\nCreated: 2026-02-26\nUpdated: 2026-04-05 - v2.0.0 Gemma 4 預設 reranking + adaptive weights + quick rerank", "mtime": 1775721124.1537395, "class_count": 0, "$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
