INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61015, $$app.services.ai.document.attachment_content_indexer$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/document/attachment_content_indexer.py", "lines": 333, "docstring": "附件內容索引服務 — OCR + LLM 混合架構\n\n將 PDF/DOCX/TXT 附件的實際內容提取、分段、向量化，\n寫入 document_chunks 表供 RAG 檢索。\n\n混合策略:\n1. 文字型 PDF → pdfplumber 直接提取\n2. 掃描型 PDF → Tesseract OCR (每頁 <400 字觸發)\n3. DOCX → python-docx 段落提取\n4. TXT → UTF-8 直讀\n5. 提取文字 → DocumentChunker 分段 → Embedding 向量化\n\nVersion: 1.0.0\nCreated: 2026-03-29", "mtime": 1775732856.3172553, "class_count": 1, "function_cou$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
