INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61198, $$app.services.ai.federation.federation_client$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/federation/federation_client.py", "lines": 269, "docstring": "Federation Client -- 聯邦式 AI 系統間呼叫客戶端 v4.1.0\n\n啟用 CK_Missive 智能體委派查詢至外部 AI 系統。\nv4.1: 拆分重構 — 服務發現移至 federation_discovery，委派移至 federation_delegation\nv4.0: D1-3 跨域委派 — 新增 delegate() 方法，透過 NemoClaw Gateway 將任務\n      委派至其他插件（如 ck-tunnel、ck-lvrland），支援直接路由與 auto 模式。\nv3.0: P2 流量改道 — OpenClaw 請求改經 NemoClaw Gateway scheduler 調度，\n      享受 Queue (併發限制) + Quota (每日配額) + Priority $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (149243, $$app.core.db_query_metrics$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/db_query_metrics.py", "lines": 65, "docstring": "DB Query Duration Prometheus Metrics\n\n追蹤 SQL 查詢延遲分布（histogram）和慢查詢計數。\n搭配 SQLAlchemy event listener 使用。\n\nMetrics:\n- db_query_duration_seconds (Histogram): 查詢延遲分布 by operation\n- db_query_slow_total (Counter): 慢查詢次數 (>5s)\n\nUsage:\n    from app.core.db_query_metrics import get_query_metrics\n    metrics = get_query_metrics()\n    metrics.record(operation=\"select\", duration_ms=123.4)", $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
