INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (315414, $$app.services.wiki.service$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/wiki/service.py", "lines": 471, "docstring": "LLM Wiki Service — 基於 Karpathy LLM Wiki Pattern 的知識 wiki 管理\n\n三大操作:\n- ingest: 來源 → KG + wiki 頁面 (自動建立/更新)\n- query: wiki 頁面搜尋 → 綜合回答 (有價值的存入 synthesis/)\n- lint: wiki 健康檢查 (孤立頁面、矛盾、缺失)\n\n與 KG 互補: KG=結構化關係(機器), Wiki=敘述性知識(人類)\n\nVersion: 1.0.0\nCreated: 2026-04-09", "mtime": 1779085270.911546, "class_count": 1, "function_count": 3, "method_count": 11, "is_async_module": true, "outgoing_dep$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
