INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (149231, $$app.core.db_pool_metrics$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/db_pool_metrics.py", "lines": 144, "docstring": "DB Connection Pool Prometheus 指標\n\n**v2.0.0（2026-04-18）** — 修正 active gauge 負值漂移：\n原實作以 checkout/checkin event 做 inc/dec，連線 invalidate / reset / recycle 會觸發\n未匹配的 checkin，長時間運行後 gauge 偏離（觀察到 -4.0）。改用 SQLAlchemy pool\n狀態直讀（``pool.checkedout()``），scrape 時抓當下真值，天然正值且永不漂移。\n\nMetrics:\n- db_pool_connections_active (Gauge): 當前 checked-out 連線數（scrape 時讀取）\n- db_pool_size (Gauge): 池內總連線（含 overflow）$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (581645, $$app.core.ck_sso$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/ck_sso.py", "lines": 329, "docstring": "CK SSO Cookie 驗證模組\n\n驗證來自 www.cksurvey.tw 的 ck_employee / ck_employee_rs SSO JWT cookie。\n\n對應端：Cloudflare Pages Functions `functions/auth/_lib/jwt.ts`（CK_Website repo）\n\nv2.0 (2026-05-24) — ADR-0008 階段 2 落地：\n    - 加 verify_ck_sso_jwt_rs256()：RS256 path + jwks fetch + in-memory cache\n    - 加 verify_ck_sso_jwt_auto()：智能 dispatcher（優先 RS256，fallback HS256）\n    - 保留 verify_ck_sso_jwt()：HS256 path 向後$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
