INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60732, $$app.services.ai.agent.agent_planner$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_planner.py", "lines": 665, "docstring": "Agent 規劃模組 — 意圖前處理、LLM 工具規劃、ReAct 循環、自動修正\n\n流程：\n1. _preprocess_question → 4 層意圖解析提取結構化 hints\n2. plan_tools → LLM Few-shot 規劃 + hints 合併 + 空計劃修復\n3. evaluate_and_replan → 快速路徑（規則自動修正） + 慢路徑（LLM ReAct）\n4. react → LLM 觀察工具結果，決定下一步行動或生成回答\n\nExtracted from agent_orchestrator.py v1.8.0\nUpdated: v2.4.0 — ReAct 循環 + 工作記憶\nUpdated: v2.8.0 — Cross-session Learning 啟動注入\nUpdated: v2.9.0$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
