INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (111594, $$app.services.ai.agent.shadow_logger$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/shadow_logger.py", "lines": 254, "docstring": "Shadow Logger — 被動記錄 /ai/agent/query_sync 的 trace，用於 Haiku vs Gemma 基線評估。\n\n設計原則：\n  - 完全被動、不阻塞主流程（async fire-and-forget）\n  - 寫 SQLite 單檔（logs/shadow_trace.db），不動 Postgres\n  - 任何寫入錯誤都 log warning、絕不拋出\n  - 預設 30% 取樣率，避免量大時 IO 壓力\n  - question/answer 入庫前做 PII 遮罩（身分證/電話/email）\n\n啟用：\n  SHADOW_ENABLED=1 SHADOW_SAMPLE_RATIO=0.3\n\n報告：\n  node scripts/checks/shadow-baseline-report.c$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
