INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61125, $$app.services.ai.domain.cross_domain_linker$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/cross_domain_linker.py", "lines": 415, "docstring": "跨專案實體自動連結服務 (Cross-Domain Entity Linker)\n\n在聯邦貢獻完成後，自動偵測不同來源專案間可連結的實體，\n建立跨域關係 (contracted_by, located_at, part_of_project, commissioned_by)。\n\n連結規則：\n1. Contractor bridging: Tunnel contractor ↔ Missive org (fuzzy ≥ 0.85)\n2. Location bridging: Missive location ↔ LvrLand land_parcel (section name)\n3. Project bridging: Missive project ↔ Tunnel tunnel (name similarity ≥ 0.8$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (223496, $$app.core.admin_push_metrics$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/core/admin_push_metrics.py", "lines": 94, "docstring": "Admin Push Prometheus 指標\n\n追蹤 admin 推播通道（LINE / Telegram / 其他）的成功失敗率。\n\n背景：2026-04-21 Telegram 個人號永封（ADR-0027），LINE 成為唯一 admin push 通道。\n為防 LINE 也發生異常導致 push 靜默失敗，新增此 metrics + 連續失敗告警。\n\nMetrics:\n- admin_push_total{channel, status}: 推播次數（status = success|fail）\n- admin_push_consecutive_failures{channel}: 連續失敗次數（gauge）", "mtime": 1776813372.5016336, "class_count": 1, "function_count": 1,$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
