INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60796, $$app.services.ai.agent.agent_summarizer$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_summarizer.py", "lines": 460, "docstring": "Agent Conversation Summarizer — 長對話摘要壓縮\n\n3-Tier Adaptive Compaction：\n- Tier 1: 完整 LLM 摘要（Full）\n- Tier 2: 部分摘要（跳過超長訊息）\n- Tier 3: 元數據降級（純規則，無 LLM）\n\nPhase 3A 升級：\n- 學習雙寫：Redis（快取）+ PostgreSQL（永久保存）\n- 3-Tier 降級壓縮策略\n- 持久化學習注入 effective_history\n\nVersion: 2.0.0\nCreated: 2026-03-14\nUpdated: 2026-03-15 - v2.0.0 3-Tier Compaction + DB 持久化", "mtime": 1776382029.5575573, "class$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60851, $$app.services.ai.agent.agent_tools$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_tools.py", "lines": 489, "docstring": "Agent 工具模組 — 20 個工具定義與實作\n\n工具清單：\n- search_documents: 向量+SQL 混合公文搜尋 + Hybrid Reranking + 圖增強鄰域擴展\n- search_dispatch_orders: 派工單搜尋 (桃園工務局)\n- search_entities: 知識圖譜實體搜尋\n- get_entity_detail: 實體詳情 (關係+關聯公文)\n- find_similar: 語意相似公文\n- get_statistics: 圖譜 / 公文統計\n- navigate_graph: 3D 知識圖譜導航\n- summarize_entity: 實體摘要簡報\n- draw_diagram: Mermaid 圖表生成\n- find_correspondence: 派工單收發文對照查詢\n- exp$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60775, $$app.services.ai.agent.agent_self_evaluator$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_self_evaluator.py", "lines": 562, "docstring": "Agent Self-Evaluator — 每次回答自動評分 + 改進信號\n\n解決核心問題：乾坤智能體目前是「被動記錄」而非「主動進化」。\n本模組在每次回答後自動評估品質，產生改進信號，\n驅動 EvolutionScheduler 進行自動修正。\n\n進化閉環：\n    Query → Answer → SelfEvaluator → Score + Signals\n                                         ↓\n                        EvolutionScheduler → Auto-Improve\n\nPhase 8: Hierarchical Evaluation Signals\n    - 4 severity levels: CRITICAL / H$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
