INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (394735, $$app.services.ai.search.optimizer$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/optimizer.py", "lines": 428, "docstring": "搜尋查詢優化服務\n\n提供高效能的全文搜尋與智能查詢優化功能\n\n優化策略：\n1. 使用 PostgreSQL pg_trgm 進行模糊匹配\n2. 智能關鍵字分詞處理\n3. 搜尋結果快取\n4. 查詢計畫優化\n\n版本: 1.0.0\n日期: 2026-01-08", "mtime": 1777976978.8849854, "class_count": 2, "function_count": 0, "method_count": 12, "is_async_module": true, "outgoing_deps": 0, "incoming_deps": 0, "layer": "services"}$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
