INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60823, $$app.services.ai.agent.agent_synthesis$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_synthesis.py", "lines": 572, "docstring": "Agent 合成模組 — 答案合成、thinking 過濾、context 建構\n\n職責：\n- synthesize_answer: 根據工具結果串流生成最終回答\n- strip_thinking: 從 LLM 回答中提取真正答案（5 階段策略，適用 Gemma 4 / Qwen3 等）\n- build_synthesis_context: 將工具結果建構為 LLM 上下文\n- summarize_tool_result: 生成工具結果的簡短摘要\n- fallback_rag: 無工具直接回答時回退到 RAG\n\nExtracted from agent_orchestrator.py v1.8.0", "mtime": 1778913482.6186385, "class_count": 1, "function_count": 0, $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (394772, $$app.services.io_import.excel_service$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/io_import/excel_service.py", "lines": 450, "docstring": "Excel 匯入服務 - 手動公文匯入（紙本郵寄等）\n\n繼承 ImportBaseService，使用統一的驗證與處理邏輯。\n\n與 CSV 匯入（電子公文檔匯入）不同：\n- CSV 匯入：電子公文系統匯出的格式，欄位固定\n- Excel 匯入：使用本系統匯出的 Excel 格式，支援新增/更新\n\n匯入欄位對應：\n- 公文ID: 有值=更新現有資料，空白=新增\n- 流水號: 新增時自動生成（S/R+序號）\n- 其他欄位: 直接匯入\n\n智慧關聯機制：\n- 發文單位/受文單位：使用 AgencyMatcher 智慧匹配/建立機關\n- 承攬案件：使用 ProjectMatcher 智慧匹配/建立案件", "mtime": 1777996336.248, "class_count": 1, "function_count": 0, "m$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
