INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (291053, $$app.services.tender.ezbid_scraper$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/tender/ezbid_scraper.py", "lines": 405, "docstring": "ezbid.tw 標案爬蟲 — 即時資料補充源\n\n爬取 cf.ezbid.tw 最新標案列表，補充 g0v PCC API 1-5 天的資料延遲。\n資料來源: https://cf.ezbid.tw (每日 3 次與 PCC 同步)\n\n用法:\n    scraper = EzbidScraper(redis_client)\n    records = await scraper.fetch_latest(category='WORK', pages=2)\n\nVersion: 1.0.0", "mtime": 1777326057.167251, "class_count": 1, "function_count": 0, "method_count": 12, "is_async_module": true, "outgoing_deps": $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
