INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (133702, $$app.api.endpoints.ai.agent_capability$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/api/endpoints/ai/agent_capability.py", "lines": 432, "docstring": "Agent 能力自覺 + 跨專案聯邦 API 端點\n\n包含:\n- Agent 能力自覺 (capability-profile, mirror-report, self-profile)\n- Agent 主動提醒 (proactive-alerts)\n- 跨專案聯邦 (federated-contribute, federated-search, cross-domain-link/path)\n\nVersion: 2.0.0 — 重命名自 agent_nemoclaw.py (ADR-0014/0015)\nCreated: 2026-03-29\nUpdated: 2026-04-16", "mtime": 1776483292.3371053, "class_count": 0, "function_count": 14, "metho$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60839, $$app.services.ai.agent.agent_tool_monitor$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_tool_monitor.py", "lines": 295, "docstring": "Agent Tool Monitor — 工具成功率監控與自動降級\n\n基於 Redis 滑動窗口，追蹤每個工具的：\n- 呼叫次數、成功/失敗/超時計數\n- 平均延遲、平均結果數\n- 近 N 次呼叫成功率（滑動窗口）\n\n降級策略：\n- 滑動窗口成功率 < degraded_threshold → 自動降級\n- 降級期間每 probe_interval 秒嘗試一次探測\n- 成功率恢復 > recovery_threshold → 自動解除\n\n設計原則：\n- Redis 不可用時靜默降級（所有方法回傳安全預設值）\n- 零侵入：只需在 AgentTrace.flush_to_monitor() 呼叫\n\nVersion: 1.0.0\nCreated: 2026-03-14", "mtime": 1775732852.2827$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60725, $$app.services.ai.agent.agent_plan_enricher$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_plan_enricher.py", "lines": 158, "docstring": "Agent 計劃充實器 — 合併 hints + 強制工具注入\n\n從 agent_planner.py 提取的計劃後處理邏輯：\n- _merge_hints_into_plan: 合併預處理 hints 到 LLM plan\n- _build_forced_calls: 空計劃時的強制工具呼叫\n- _build_fallback_plan: 規劃失敗回退\n\nVersion: 1.0.0 (拆分自 agent_planner v2.9.0)\nCreated: 2026-03-25", "mtime": 1775721124.0878065, "class_count": 0, "function_count": 6, "method_count": 0, "is_async_module": false, "outgoing_dep$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290877, $$app.services.integration.line_bot$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/integration/line_bot.py", "lines": 428, "docstring": "LINE Bot Service — LINE Messaging API 整合服務\n\n提供：\n- HMAC-SHA256 Webhook 簽名驗證\n- 文字訊息 → AgentOrchestrator 同步問答 → LINE 回覆\n- 語音訊息 → VoiceTranscriber 轉文字 → AgentOrchestrator 問答 → LINE 回覆\n- 圖片訊息 → OCR 發票辨識 → 建立費用紀錄 → LINE 回覆\n- Push 通知（截止日提醒、異常警報）\n\nVersion: 1.2.0\nCreated: 2026-03-15\nUpdated: 2026-03-23 - v1.2.0 Image → OCR invoice parsing", "mtime": 1777308318.1758597, "class_count$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
