INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (72873, $$app.services.coding_helpers$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/coding_helpers.py", "lines": 87, "docstring": "編碼生成輔助工具 (ADR-0013 併發保護)\n\n提供 `retry_on_code_conflict` helper — 在自動生成業務碼 (billing_code /\ninvoice_ref / ledger_code / asset_code) 時處理高併發 race condition。\n\n背景:\n- 生成器 `CaseCodeService.generate_*_code` 使用 `SELECT MAX(code) + 1` 策略\n- 兩個並行 request 可能同時讀到相同 max → 產生相同 next_serial\n- DB 有 unique constraint，後 flush 的那筆會 `IntegrityError`\n- 此 helper 在錯誤時 rollback savepoint 並重試，重新生成下一個序號\n\n設計抉擇:$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61173, $$app.services.ai.domain.morning_report_service$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/domain/morning_report_service.py", "lines": 1074, "docstring": "Morning Report Service — 每日晨報自動生成 + 推送\n\n每日早上 8:00 自動彙整：\n1. 今日到期派工單\n2. 逾期未結案項目\n3. 待審核費用\n4. 近期里程碑\n5. 新收公文\n6. 標案訂閱通知\n\n透過 Gemma 4 合成自然語言摘要，推送到 Telegram/LINE。\n\nVersion: 2.0.0 — 格式化邏輯拆分至 morning_report_formatter.py", "mtime": 1776995844.2068431, "class_count": 1, "function_count": 1, "method_count": 18, "is_async_module": true, "outgoing_deps": 0, "incoming_deps": $$, 'knowledge') ON CONFLICT (id) DO NOTHING;
