INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (134281, $$app.services.ai.misc.missive_agent$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/misc/missive_agent.py", "lines": 157, "docstring": "Missive Agent — 自覺型 Agent\n\n包裝 AgentOrchestrator，加入自我覺察 (self-awareness)、\n用戶上下文、主動提醒等增強功能。\n\n流程:\n1. 載入自我檔案 + 沙箱策略\n2. 載入用戶偏好\n3. 檢查主動提醒\n4. 規劃+執行 (Agent pipeline)\n5. 自省+記錄教訓\n\nVersion: 3.0.0 — 重命名自 NemoClawAgent (ADR-0014/0015 廢止後)", "mtime": 1777083828.5735471, "class_count": 1, "function_count": 0, "method_count": 4, "is_async_module": true, "outgoing_deps": 0, "incoming_dep$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
