INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60582, $$app.services.ai.agent.agent_auto_corrector$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_auto_corrector.py", "lines": 172, "docstring": "Agent 自動修正模組 -- 規則式工具結果評估與重試策略\n\n從 agent_planner.py 提取，提供 6 種策略：\n1. search_documents 0 結果 -> 放寬條件重試\n2. search_entities 0 結果 -> 改用文件搜尋\n2.5. search_documents 重試無果 -> 嘗試派工單搜尋\n3. 全部無結果 -> 統計概覽\n4. find_similar 錯誤 -> 改用文件搜尋\n5. search_entities 有結果 -> 展開實體詳情\n6. search_dispatch_orders 有結果 -> 追查收發文配對", "mtime": 1775721124.0817575, "class_count": 0, "function_count": 1, "method$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290373, $$app.services.agency.core$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/agency/core.py", "lines": 198, "docstring": "機關服務層 - CRUD + 搜尋\n\n工廠模式，db session 在建構函數注入。\n統計功能已拆分至 AgencyStatisticsService。\n匹配功能已拆分至 AgencyMatchingService。\n\n版本: 4.1.0\n更新日期: 2026-03-23\n變更: 遷移至 Repository 層 (A7) — 消除直接 db.execute()\n\n使用方式:\n    from app.core.dependencies import get_service\n    from app.services.agency_service import AgencyService\n\n    @router.get(\"/agencies\")\n    async def list_agencies(\n        service: Ag$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60703, $$app.services.ai.agent.agent_pattern_learner$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_pattern_learner.py", "lines": 510, "docstring": "Agent Pattern Learner — 使用者查詢模式學習\n\n從每次成功問答中學習查詢模式：\n- 正規化問題 → 模板 (e.g. \"{ORG}的{DOC_TYPE}\" )\n- 記錄成功的工具呼叫序列 + 參數模板\n- 後續相似查詢可直接匹配模式，跳過 LLM 規劃\n\nPhase 3A 升級：語意匹配 fallback\n- 精確 MD5 匹配失敗時，使用 embedding 餘弦相似度比對\n- 可配置閾值 + kill switch\n\n設計原則：\n- Redis 不可用時靜默降級\n- 模式數量上限（防止記憶體膨脹）\n- 衰減權重（近期模式權重更高）\n- 高信心門檻（寧可多走 LLM，不可錯誤路由）\n\nVersion: 2.0.0\nCreated: 2026-03-14\nUpdated: 202$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (60810, $$app.services.ai.agent.agent_supervisor$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/agent/agent_supervisor.py", "lines": 374, "docstring": "Agent Supervisor — 多 Agent 協調編排\n\n當複合型問題跨越多個領域（公文 + 專案 + ERP），Supervisor 負責：\n1. 意圖拆解：將複合問題拆為子任務\n2. 並行委派：將子任務分配到對應 Agent 上下文\n3. 結果合併：將多個 Agent 結果合成統一回覆\n\n依賴：\n- AgentPlanner: 規劃子任務\n- AgentToolExecutor: 執行工具\n- AgentSynthesizer: 合成答案\n- ToolRegistry: 上下文篩選工具\n\nVersion: 1.0.0\nCreated: 2026-03-15", "mtime": 1775732863.1631148, "class_count": 3, "function_count": 1, "method_c$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
