INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (61559, $$app.services.ai.search.rag_retrieval$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/ai/search/rag_retrieval.py", "lines": 381, "docstring": "RAG 檢索與上下文建構模組\n\n從 rag_query_service.py 拆分，負責：\n1. 知識圖譜查詢擴展 (KG neighbor expansion)\n2. 段落級 / 文件級向量檢索\n3. Hybrid Reranking (向量 + BM25 + 關鍵字覆蓋度)\n4. LLM 上下文建構\n5. 查詢詞提取 (jieba + regex fallback)\n\nVersion: 1.0.0\nCreated: 2026-03-26 (extracted from rag_query_service.py v2.4.0)", "mtime": 1777333150.8406353, "class_count": 0, "function_count": 6, "method_count": 0, "is_async_module$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
