INSERT INTO canonical_entities (id, canonical_name, entity_type, description, graph_domain) VALUES (290468, $$app.services.contract.case_code$$, $$py_module$$, $${"file_path": "D:/CKProject/CK_Missive/backend/app/services/contract/case_code.py", "lines": 511, "docstring": "統一案號編碼服務\n\n參照公文系統專案編碼機制 CK{年度}_{類別}_{性質}_{流水號}，擴充為跨模組統一案號。\n\n編碼格式: CK{年度4碼}_{模組2碼}_{類別2碼}_{流水號3碼}\n\n模組代碼:\n  PM = 專案管理 (Project Management)\n  FN = 財務管理 (Finance/ERP)\n  DP = 派工管理 (Dispatch)\n  GN = 一般委辦 (General，相容既有 contract_projects)\n\n類別代碼 (依模組):\n  PM: 01=委辦招標, 02=承攬報價\n  FN: 01=報價單, 02=變更單, 03=追加減, 99=其他\n  DP: 01=地上物, 02=土地查估, 03=計畫書, 04=測量, 99=其他\n  GN: 01=委辦招標, 02=承攬報價\n\n$$, 'knowledge') ON CONFLICT (id) DO NOTHING;
